+            sql,
+            duckdb::params![
+                entry.entry_type.as_str(),
+                &entry.title,
+                &entry.summary,
+                &entry.content,
+                &entry.source_session_id,
+                &entry.source_file,
+                &entry.source_lines,
+                &tags_json,
+                entry.created_at.to_rfc3339(),
+                entry.usefulness_score,
+                entry.view_count,
+                entry.applied_count,
+            ],
+            |row| row.get(0),
+        )?;
+
+        Ok(id)
+    }
